379	// OperatorPromptApprove implements the operatorPromptApprove mutation:
380	// validates CSRF, verifies the bead is a proposed operator-prompt, enforces
381	// the per-project allowlist (ts-net identities are never eligible per
382	// locked decision), transitions proposed → open, and appends an audit event
383	// recording the approver.
384	func (r *mutationResolver) OperatorPromptApprove(ctx context.Context, id string) (*OperatorPromptApproveResult, error) {
385		httpReq, ident, err := r.requireOperatorPromptCSRF(ctx)
386		if err != nil {
387			return nil, err
388		}
389		if !r.canAutoApprove(ident) {
390			return nil, errAutoApproveDenied
391		}
392	
393		store := r.beadStore()
394		existing, err := store.Get(id)
395		if err != nil {
396			return nil, err
397		}
398		if existing.IssueType != bead.IssueTypeOperatorPrompt {
399			return nil, fmt.Errorf("operator-prompts: bead %s is not an operator-prompt (issue_type=%q)", id, existing.IssueType)
400		}
401		if existing.Status != bead.StatusProposed {
402			return nil, fmt.Errorf("operator-prompts: bead %s is not in proposed status (got %q); cannot approve", id, existing.Status)
403		}
404		if err := store.Update(id, func(b *bead.Bead) {
405			b.Status = bead.StatusOpen
406		}); err != nil {
407			return nil, err
408		}
409		if err := store.AppendEvent(id, bead.BeadEvent{
410			Kind:    OperatorPromptApproveEventKind,
411			Summary: "operator prompt approved",
412			Body:    fmt.Sprintf("identity=%s actor=%s remote_addr=%s", ident.kind, ident.actor, httpReq.RemoteAddr),
413			Actor:   ident.actor,
414			Source:  "graphql:operatorPromptApprove",
415		}); err != nil {
416			return nil, fmt.Errorf("operator-prompts: append approve audit event: %w", err)
417		}
418		persisted, err := store.Get(id)
419		if err != nil {
420			return nil, err
421		}
422		return &OperatorPromptApproveResult{Bead: beadModelFromBead(persisted)}, nil
423	}
