584	// newRequestID returns a 16-byte hex random string used as the request ID
585	// recorded on the audit event when the caller does not supply X-Request-Id.
586	func newRequestID() string {
587		var buf [16]byte
588		if _, err := rand.Read(buf[:]); err != nil {
589			return "no-request-id"
590		}
591		return hex.EncodeToString(buf[:])
592	}
